import{_ as t,o as r,c as e,a3 as i}from"./chunks/framework.BveOjhN0.js";const u=JSON.parse('{"title":"XiHan.BasicApp 基础应用","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/basic-app/index.md","filePath":"cosmos/basic-app/index.md","lastUpdated":1783221783000}'),o={name:"cosmos/basic-app/index.md"};function n(s,a,d,l,h,p){return r(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="xihan-basicapp-基础应用" tabindex="-1">XiHan.BasicApp 基础应用 <a class="header-anchor" href="#xihan-basicapp-基础应用" aria-label="Permalink to &quot;XiHan.BasicApp 基础应用&quot;">​</a></h1><p><strong>企业级中后台内核。</strong> 后端基于 .NET 10 与 <a href="./../framework/">XiHan.Framework</a>，前端基于 Vue 3，开箱即带多租户、RBAC + ABAC 权限、代码生成与实时通信等能力。它既是一套可直接投产的中后台起点，也是学习 .NET + Vue 全栈实践、以及 XiHan.Framework 用法的最佳参考。</p><blockquote><p>后端与前端当前版本：<strong>v2.3.1</strong>。全部开源，MIT 许可。</p></blockquote><h2 id="它是什么" tabindex="-1">它是什么 <a class="header-anchor" href="#它是什么" aria-label="Permalink to &quot;它是什么&quot;">​</a></h2><p>XiHan.BasicApp 采用<strong>前后端分离</strong>架构：</p><ul><li><strong>后端</strong> 遵循 DDD 分层与 CQRS，应用服务经<strong>动态 API</strong> 直接暴露为 REST 接口，无需写 Controller</li><li><strong>前端</strong> 使用 Vue 3 + TypeScript + Naive UI，Schema 驱动的列表页、权限/租户/偏好三重感知</li></ul><p>系统内置完整的身份、权限、租户与审计能力。你可以拿它当项目脚手架直接改，也可以只读它的代码学习框架怎么用。</p><h2 id="从这里开始" tabindex="-1">从这里开始 <a class="header-anchor" href="#从这里开始" aria-label="Permalink to &quot;从这里开始&quot;">​</a></h2><div class="tip custom-block" style="padding-top:8px;"><ol><li><a href="./getting-started"><strong>快速开始</strong></a> —— 在本地把前后端跑起来（约 10 分钟）</li><li><a href="./architecture"><strong>系统架构</strong></a> —— 看懂后端模块划分与前后端协作</li><li><a href="./permissions"><strong>权限模型</strong></a> —— 理解 RBAC + ABAC、数据范围、多租户隔离</li></ol></div><h2 id="文档地图" tabindex="-1">文档地图 <a class="header-anchor" href="#文档地图" aria-label="Permalink to &quot;文档地图&quot;">​</a></h2><table tabindex="0"><thead><tr><th>板块</th><th>内容</th></tr></thead><tbody><tr><td><a href="./overview">系统概述</a></td><td>定位、技术栈、能力全景</td></tr><tr><td><a href="./getting-started">快速开始</a></td><td>环境要求、后端 / 前端 / 数据库启动、默认账号</td></tr><tr><td><a href="./architecture">系统架构</a></td><td>后端模块（Core / Web.Core / Saas / CodeGeneration / WebHost）与前端结构</td></tr><tr><td><a href="./features">功能清单</a></td><td>身份、权限、多租户、审计、代码生成、平台能力、前端体验</td></tr><tr><td><a href="./permissions">权限模型</a></td><td>RBAC + ABAC、权限码、数据范围、字段脱敏、租户版本门控</td></tr><tr><td><a href="./deployment">部署</a></td><td>Linux systemd / Windows 部署</td></tr><tr><td><a href="./changelog">更新日志</a></td><td>各版本变更记录（新增 / 修复 / 优化 / 调整 / 升级 / 移除）</td></tr></tbody></table><h2 id="技术栈速览" tabindex="-1">技术栈速览 <a class="header-anchor" href="#技术栈速览" aria-label="Permalink to &quot;技术栈速览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>端</th><th>关键技术</th></tr></thead><tbody><tr><td>后端</td><td>.NET 10 · XiHan.Framework 2.5.x · SqlSugar（PostgreSQL/MySQL/MariaDB）· Redis · SignalR · Serilog · Scalar</td></tr><tr><td>前端</td><td>Vue 3.5+ · TypeScript 5.9+ · Vite 6 · Naive UI · Pinia · Tailwind CSS 4 · Tiptap · vue-i18n</td></tr></tbody></table><h2 id="在线体验" tabindex="-1">在线体验 <a class="header-anchor" href="#在线体验" aria-label="Permalink to &quot;在线体验&quot;">​</a></h2><ul><li><strong>在线用例</strong>：<a href="https://basicapp.xihanfun.com" target="_blank" rel="noreferrer">https://basicapp.xihanfun.com</a></li><li><strong>源码</strong>：<a href="https://github.com/XiHanFun/XiHan.BasicApp" target="_blank" rel="noreferrer">GitHub</a> · <a href="https://gitee.com/XiHanFun/XiHan.BasicApp" target="_blank" rel="noreferrer">Gitee</a></li></ul><h2 id="与-xihan-framework-的关系" tabindex="-1">与 XiHan.Framework 的关系 <a class="header-anchor" href="#与-xihan-framework-的关系" aria-label="Permalink to &quot;与 XiHan.Framework 的关系&quot;">​</a></h2><p>XiHan.BasicApp 构建在 <a href="./../framework/">XiHan.Framework</a> 之上——框架提供认证、授权、数据、缓存、事件总线、多租户、动态 API 等底层能力，BasicApp 在其上实现具体的中后台业务。想先理解底层机制，建议先读<a href="./../framework/quickstart">框架快速上手</a>。</p>',17)])])}const f=t(o,[["render",n]]);export{u as __pageData,f as default}